import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is the difference between mean and median?", a: "Mean is the arithmetic average found by dividing the sum by the count. Median is the middle value after sorting. Median is often better when the dataset has extreme outliers." },
  { q: "How do you calculate variance?", a: "Find the mean, subtract the mean from each value, square each difference, add those squared differences, then divide by n for population variance or n-1 for sample variance." },
  { q: "What is standard deviation and how is it used?", a: "Standard deviation is the square root of variance. It shows how spread out values are around the mean and is used to compare consistency, variability, and outliers." },
  { q: "What are quartiles and how do you find them?", a: "Quartiles split sorted data into four parts. Q2 is the median, Q1 is the median of the lower half, and Q3 is the median of the upper half." },
  { q: "When should you use median instead of mean?", a: "Use median when data has outliers or strong skew. For example, median income often represents a typical person better than mean income because very high values can pull the mean upward." },
];

const parseNums = (input: string) => input.split(/[\s,;]+/).map(Number).filter((n) => Number.isFinite(n));
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Invalid";
const medianOf = (values: number[]) => {
  if (!values.length) return 0;
  const mid = Math.floor(values.length / 2);
  return values.length % 2 ? values[mid] : (values[mid - 1] + values[mid]) / 2;
};

export default function StatisticsCalculator() {
  const [input, setInput] = useState("4, 8, 15, 16, 23, 42");
  const stats = useMemo(() => {
    const nums = parseNums(input);
    if (!nums.length) return null;
    const sorted = [...nums].sort((a, b) => a - b);
    const count = nums.length;
    const sum = nums.reduce((total, value) => total + value, 0);
    const mean = sum / count;
    const median = medianOf(sorted);
    const counts = new Map<number, number>();
    nums.forEach((value) => counts.set(value, (counts.get(value) || 0) + 1));
    const maxCount = Math.max(...counts.values());
    const modes = maxCount > 1 ? [...counts.entries()].filter(([, c]) => c === maxCount).map(([value]) => value) : [];
    const variance = nums.reduce((total, value) => total + (value - mean) ** 2, 0) / count;
    const sd = Math.sqrt(variance);
    const lower = sorted.slice(0, Math.floor(count / 2));
    const upper = sorted.slice(Math.ceil(count / 2));
    const q1 = medianOf(lower);
    const q3 = medianOf(upper);
    return { nums, sorted, count, sum, mean, median, mode: modes.length ? modes.join(", ") : "No mode", min: sorted[0], max: sorted[count - 1], range: sorted[count - 1] - sorted[0], variance, sd, q1, q2: median, q3, iqr: q3 - q1 };
  }, [input]);

  return (
    <>
      <SEOHead title="Free Statistics Calculator Online - Calculate Mean Median Mode and More Instantly | CalcHive" description="Free online statistics calculator. Calculate mean, median, mode, range, variance, standard deviation, quartiles and more from any dataset instantly. 100% free for students, no signup required." canonical="/statistics-calculator" keywords="free statistics calculator, mean median mode calculator free online, statistics calculator online free, dataset statistics calculator free, descriptive statistics calculator free" category="Statistics Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Statistics Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free statistics calculator to calculate mean, median, mode, range, variance, standard deviation, quartiles, and more from any dataset.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <label htmlFor="dataset" className="text-sm font-semibold text-foreground block mb-2">Dataset</label>
          <textarea id="dataset" value={input} onChange={(event) => setInput(event.target.value)} rows={3} className="w-full px-4 py-3 rounded-xl border border-input bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all font-mono text-sm mb-6" />
          {stats ? <motion.div key={input} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 mb-4 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Mean</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-statistics">{fmt(stats.mean)}</p><p className="text-white/70 text-sm mt-1">Count: {stats.count} - Sum: {fmt(stats.sum)}</p></div>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">{[
              ["Median", fmt(stats.median)], ["Mode", stats.mode], ["Range", fmt(stats.range)], ["Variance", fmt(stats.variance)], ["Std. Deviation", fmt(stats.sd)], ["Minimum", fmt(stats.min)], ["Maximum", fmt(stats.max)], ["Q1", fmt(stats.q1)], ["Q2", fmt(stats.q2)], ["Q3", fmt(stats.q3)], ["IQR", fmt(stats.iqr)], ["Sorted", stats.sorted.join(", ")],
            ].map(([label, value]) => <div key={label} className="bg-accent/60 border border-border rounded-xl p-3 text-center"><p className="text-xs text-muted-foreground font-medium mb-1">{label}</p><p className="text-sm font-extrabold text-foreground break-words">{value}</p></div>)}</div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">Mean = {fmt(stats.sum)} / {stats.count} = {fmt(stats.mean)}. Range = {fmt(stats.max)} - {fmt(stats.min)} = {fmt(stats.range)}. Variance = average squared distance from the mean = {fmt(stats.variance)}. Standard deviation = sqrt(variance) = {fmt(stats.sd)}.</p></div>
          </motion.div> : <p className="text-center text-muted-foreground py-4">Enter at least one number.</p>}
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate All Basic Statistics for Any Dataset for Free</h2><p className="text-muted-foreground leading-relaxed">Enter comma-separated values and this dataset statistics calculator free tool sorts the numbers, counts them, sums them, and calculates descriptive statistics instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">Mean Median Mode Range Variance and Standard Deviation Explained</h2><p className="text-muted-foreground leading-relaxed">Mean is the average, median is the middle, mode is the most repeated value, range is max minus min, variance measures spread, and standard deviation is the square root of variance.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Data Statistics Tool for Students and Researchers</h2><p className="text-muted-foreground leading-relaxed">Use this statistics calculator online free for homework, research summaries, quality checks, and quick descriptive statistics.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/statistics-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


